#!/bin/bash
set -e
echo '💳 Applying GACOM Paystack fix...'
mkdir -p supabase/functions/paystack-init

echo '  ✅ writing lib/core/services/paystack_service.dart'
echo '' | base64 -d > lib/core/services/paystack_service.dart

echo '  ✅ writing lib/features/store/screens/cart_screen.dart'
echo '' | base64 -d > lib/features/store/screens/cart_screen.dart

echo '  ✅ writing lib/features/wallet/screens/wallet_screen.dart'
echo '' | base64 -d > lib/features/wallet/screens/wallet_screen.dart

echo '  ✅ writing supabase/functions/paystack-init/index.ts'
echo '' | base64 -d > supabase/functions/paystack-init/index.ts

echo ''
echo '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
echo '✅ Files written. Now do these 3 steps:'
echo ''
echo 'STEP 1 — Add your Paystack SECRET key to Supabase:'
echo '  Go to: Supabase Dashboard → Edge Functions → Secrets'
echo '  Add secret:  PAYSTACK_SECRET_KEY = sk_live_xxxx'
echo ''
echo 'STEP 2 — Deploy the Edge Function:'
echo '  npx supabase functions deploy paystack-init --no-verify-jwt'
echo ''
echo 'STEP 3 — Push code:'
echo '  git add lib/ supabase/'
echo '  git commit -m "fix: paystack via edge function"'
echo '  git push origin main'
echo '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
